mapper.sql:
SELECT HE.EMPID, HE.LOCAL_NAME, AR.ITEM_NO, GET_DEPT_NAME(HE.DEPTNO, #{lang, jdbcType=VARCHAR}) DEPT_NAME, GET_GLOBAL_NAME(AR.SHIFT_NO, #{lang, jdbcType=VARCHAR}) SHIFT_NAME, HE.POST_GRADE_NO, GET_GLOBAL_NAME(HE.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) POST_GRADE_NAME, GET_GLOBAL_NAME(AR.ITEM_NO, #{lang, jdbcType=VARCHAR}) ITEM_NAME, AR.AR_DATE_STR AS AR_DATE_STR, TO_CHAR(AR.FROM_TIME, 'YYYY/MM/DD HH24:MI') FROM_DATE, TO_CHAR(AR.TO_TIME, 'YYYY/MM/DD HH24:MI') TO_TIME, AR.QUANTITY, AR.UNIT, AR.REMARK, GET_GLOBAL_NAME(AR.STATUS_CODE, #{lang, jdbcType=VARCHAR}) STATUS_NAME, AR.LOCK_YN FROM AR_DETAIL_HTSV AR, HR_EMPLOYEE HE WHERE AR.PERSON_ID = HE.PERSON_ID AND AR.PERSON_ID NOT LIKE '111111%' AND AR.ITEM_NO NOT IN ( '90000295', '90000296', '90000297', '90000298', '90000299', '90000300', '90000301' ) AND AR.AR_DATE_STR >= #{startDate, jdbcType=VARCHAR} AND AR.AR_DATE_STR <= #{endDate, jdbcType=VARCHAR} AND EXISTS ( SELECT B1.DEPTID FROM HR_DEPARTMENT B1 WHERE B1.DEPTNO = HE.DEPTNO START WITH B1.DEPTNO IN ( SELECT HRD.DEPTID FROM HR_DEPARTMENT HRD WHERE HRD.MANAGER_EMP_ID = #{adminID, jdbcType=VARCHAR} ) CONNECT BY PRIOR B1.DEPTNO = B1.PARENT_DEPT_NO UNION SELECT AR_SUPERVISOR_INFO.DEPTNO FROM AR_SUPERVISOR_INFO WHERE AR_SUPERVISOR_INFO.DEPTNO = HE.DEPTNO AND AR_SUPERVISOR_INFO.PERSON_ID = #{adminID, jdbcType=VARCHAR} )
AND ( UPPER(HE.EMPID) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' OR CONVERTTOUNSIGN(UPPER(HE.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{keyword, jdbcType=VARCHAR})) || '%' )
AND INSTR(',' || #{deptNos, jdbcType=VARCHAR} || ',', ',' || HE.DEPTNO || ',') > 0
AND AR.SHIFT_NO = #{shiftNo, jdbcType=VARCHAR}
AND AR.ITEM_NO = #{itemNoSearch, jdbcType=VARCHAR}
AND AR.STATUS_CODE = #{statusCode, jdbcType=VARCHAR}
AND HE.POST_FAMILY = #{postFamily, jdbcType=VARCHAR}

mapper.select:
SELECT * FROM (
    SELECT INNER_Q.*, ROWNUM AS RN FROM (

        ORDER BY AR.AR_DATE_STR ASC, AR.CREATE_DATE DESC, HE.DEPTNO, HE.EMPID
    ) INNER_Q
    WHERE ROWNUM <= #{start, jdbcType=INTEGER} + #{length, jdbcType=INTEGER}
) WHERE RN > #{start, jdbcType=INTEGER}
